def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    comp = ((ratio - a) ** 7) / (a * b * 0.8 + 1)
                    priority += comp * np.tan(ratio * b / (a + 2)) * np.exp(-b/(a+1))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2
            if ratio > 10:
                for c in range(1, 5):
                    priority += np.sin(ratio * c) * np.log1p(ratio + c)
        elif 5 < ratio <= 8:
            for d in range(1, int(np.ceil(ratio * 1.5)) + 4):
                for e in range(1, d + 3):
                    factor = ((ratio - d) ** 4) * np.cos(ratio * d) / (e + 0.3)
                    priority += np.tanh(factor) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            for f in range(1, 6):
                priority += np.cos(f * ratio * i) * (ratio / (f + 1)) ** 1.2
        elif 2 <= ratio <= 5:
            s = 0
            for g in range(1, 15):
                s += ((ratio - 2) ** g) / (g * 2.1) * np.sin(g * ratio * 0.9)
            priority = (s * np.sin(8 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2
            if bin_cap < item * 1.5:
                for h in range(1, 4):
                    priority += np.sin(h * ratio * i * 0.5) * (ratio ** h) / (h + 1)
        elif 1 <= ratio < 2:
            s = 0
            for j in range(1, 12):
                s += ((2 - ratio) ** j) / (j ** 2 + 1)
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
                for k in range(1, 5):
                    penalty += np.cos(k * 30 * ratio) * 0.8
            else:
                penalty = np.sin(15 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for l in range(1, 7):
                priority += np.sin(l * ratio * i) * ((ratio - 1) ** l) / l
        elif 0.4 <= ratio < 1:
            s = 0
            for m in range(1, 20):
                s += ((1 - ratio) ** m) / (m * 5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for n in range(1, 8):
                priority += ((1 - ratio) ** n) * np.sin(n * item * 1.5) * 0.9
        elif 0.15 <= ratio < 0.4:
            s = 0
            for o in range(1, 14):
                s += ((0.4 - ratio) ** o) / (o * 3.5) * np.cos(o * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.6) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for p in range(1, 9):
                priority += ((0.4 - ratio) ** p) / (p * 7) * np.cos(item * p * 1.3)
        else:
            s = 0
            for q in range(1, 13):
                s += ((0.15 - ratio) ** q) / (q * 6) * np.sin(q * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for r in range(1, 10):
                priority += ((0.15 - ratio) ** r) / (r * 8) * np.cos(item * r * 0.7)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
            for s in range(1, 5):
                priority += np.sin(s * ratio * i * 0.7) * 0.45
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
            for t in range(1, 5):
                priority -= np.cos(t * ratio * (i + 2)) * 0.5
        for u in range(1, 5):
            if (i + u) % 4 == 0:
                priority += np.sin(ratio * (i + u) * 1.1) * 0.35
            else:
                priority -= np.cos(ratio * (i + u) * 1.1) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.65
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.65
        priorities[i] = priority
    return priorities
